import sys, json
try:
    data = json.loads(sys.stdin.read())
except Exception:
    sys.exit(0)
target_name = sys.argv[1]
def find_id(obj):
    if isinstance(obj, list):
        for item in obj:
            res = find_id(item)
            if res: return res
    elif isinstance(obj, dict):
        if obj.get("name") == target_name and "id" in obj:
            return obj["id"]
        for key, value in obj.items():
            res = find_id(value)
            if res: return res
    return None
